class Solution:
    def findLongestWord(self, s: str, dictionary: List[str]) -> str:
        def subseq(w):
            i = 0
            for c in s:
                if i < len(w) and w[i] == c:
                    i += 1
            return i == len(w)
        for w in sorted(dictionary, key=lambda x: (-len(x), x)):
            if subseq(w):
                return w
        return ""

